std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a buffer_adaptor object for the input buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    // Check if the requested bytes exceed available data
    size_t available_bytes = adaptor.size();
    if (bytes_to_peek > available_bytes) {
        bytes_to_peek = available_bytes; // Only copy available data
