struct PacketHeader {
    uint32_t magic;
    uint32_t version;  // Corrected from uint16_t to uint32_t to match typical header structure
    uint32_t flags;    // Corrected from uint16_t to uint32_t for consistency
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor instance from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create a binary_stream instance using the buffer_adaptor
    hexi::binary_stream<hexi::buffer_adaptor<std::span<const uint8_t>>> stream(adaptor);

    PacketHeader header;

    // Use binary_stream's operator>> to read each header field
    stream >> header.magic;
    stream >> header.version;
    stream >> header.flags;

    // Return the populated header structure
    return header;
}
```

