std::vector<uint8_t> write_and_serialise_packet(uint32_t header, const UserData& data) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor from the buffer
    hexi::pmc::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::pmc::binary_stream stream(adaptor);

    // Write the header using the stream's operator<<
    stream << header;

    // Serialize the UserData structure using the stream's serialise method
    stream.serialise(data);

    // Return the populated buffer
    return buffer;
}
