template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Create destination buffer with requested size
    std::vector<uint8_t> destination(bytes_to_preview);

    // Use read function with allow_optimise=false to copy data without advancing read pointer
    storage.read(destination.data(), bytes_to_preview, false);

    // Resize to actual bytes read (in case less than requested were available)
    return std::vector<uint8_t>(destination.begin(), destination.begin() + bytes_to_preview);
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Use size() function to get readable data size
    status.readable_size = storage.size();

    // Calculate free space as block_size - readable_size
    status.free_space = block_size - status.readable_size;

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use clear() function to reset both read and write offsets
    storage.clear();
}
