    // Write the data string with prefix using operator<< (automatically adds prefix)
    stream << packet.data;

    // Write 16 bytes of padding (0x00) using fill<16>(0x00)
    stream.fill<16>(0x00);

    // Write the footer using operator<<
    stream << packet.footer;

    // Return the populated buffer
    return buffer;
}
